import{_ as o,o as r,c as e,a3 as a}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"📚 知识库 - 快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/knowledge-base/index.md","filePath":"user-guide/tools/knowledge-base/index.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/knowledge-base/index.md"};function n(i,t,s,d,g,u){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="📚-知识库-快速上手" tabindex="-1">📚 知识库 - 快速上手 <a class="header-anchor" href="#📚-知识库-快速上手" aria-label="Permalink to &quot;📚 知识库 - 快速上手&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>知识库是一个<strong>本地 RAG（检索增强生成）引擎</strong>，让你能够将文档、笔记和结构化信息组织为可被 AI 智能检索的知识体系。它的核心思想是：</p><blockquote><p><strong>把信息变成 AI 能理解的&quot;知识原子&quot;，让大模型在回答时&quot;有据可查&quot;。</strong></p></blockquote><p>与普通文件管理器不同，知识库会对你存入的内容进行<strong>向量化处理</strong>，理解语义而非仅靠关键词匹配。当你向它提问时，它能从知识库中找出最相关的内容片段，作为上下文提供给 AI，从而获得更准确、更贴合你私有知识的回答。</p><div class="tip custom-block"><p class="custom-block-title">核心场景</p><ul><li>你有一堆技术文档和笔记，想让 AI 基于这些内容回答技术问题</li><li>你想整理项目经验、会议记录，构建团队知识沉淀</li><li>你希望 AI 聊天时能引用你指定的资料，而不是凭空回答</li></ul></div><h3 id="核心概念-caiu-原子知识单元" tabindex="-1">核心概念：CAIU（原子知识单元） <a class="header-anchor" href="#核心概念-caiu-原子知识单元" aria-label="Permalink to &quot;核心概念：CAIU（原子知识单元）&quot;">​</a></h3><p>知识库的最小存储单位叫做 <strong>CAIU</strong>（Core Atomic Information Unit），你可以把它理解为一个&quot;知识卡片&quot;：</p><ul><li><strong>Key</strong>：条目标题，也是唯一标识符，支持 <code>[[Key]]</code> 语法进行跨条目引用</li><li><strong>Content</strong>：Markdown 格式的正文内容</li><li><strong>Tags</strong>：带权重的标签（<code>{name, weight}</code> 结构），用于分类和语义检索</li><li><strong>Assets</strong>：关联的资产引用，指向全局 AssetManager 中的资源</li><li><strong>Priority</strong>：检索时的权重加成（数值越高越优先，默认 100）</li><li><strong>Enabled</strong>：启用状态，禁用后不会出现在搜索结果中</li><li><strong>Vector Status</strong>：向量化状态（已就绪/待处理/失败/无等）</li></ul><p>每个 CAIU <strong>不进行自动分片</strong>——你存入的一个条目就是一个完整的知识单元，系统会保持其完整性。</p><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="第一步-配置-embedding-模型" tabindex="-1">第一步：配置 Embedding 模型 <a class="header-anchor" href="#第一步-配置-embedding-模型" aria-label="Permalink to &quot;第一步：配置 Embedding 模型&quot;">​</a></h3><p>在开始使用之前，需要先配置一个用于向量化的 AI 模型：</p><ol><li>进入知识库工具的 <strong>设置</strong> 标签页</li><li>在&quot;AI 模型配置&quot;区域，选择一个支持 <strong>Embedding</strong> 功能的模型</li><li>点击 <strong>探测模型维度</strong> 按钮自动检测向量维度</li></ol><blockquote><p>TODO: 截图 - 设置页面中的 Embedding 模型选择器</p></blockquote><p>配置完成后，系统会自动保存并准备好向量化环境。</p><h3 id="第二步-创建知识库" tabindex="-1">第二步：创建知识库 <a class="header-anchor" href="#第二步-创建知识库" aria-label="Permalink to &quot;第二步：创建知识库&quot;">​</a></h3><p>在知识库列表页，点击 <strong>创建知识库</strong> 按钮：</p><ol><li>输入知识库名称（必填，同一名称不可重复）</li><li>可选的描述信息</li><li>点击确认完成创建</li></ol><p>创建完成后，会自动选中新创建的知识库进入工作区。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>你可以创建多个知识库来组织不同主题的内容——比如&quot;技术文档&quot;、&quot;产品需求&quot;、&quot;团队 Wiki&quot;等。</p></div><blockquote><p>TODO: 截图 - 创建知识库弹窗，展示名称输入框和确认按钮</p></blockquote><h3 id="第三步-导入文档" tabindex="-1">第三步：导入文档 <a class="header-anchor" href="#第三步-导入文档" aria-label="Permalink to &quot;第三步：导入文档&quot;">​</a></h3><p>创建好知识库后，在工作区可以导入内容：</p><p><strong>方式一：手动添加条目</strong></p><p>点击 <strong>添加条目</strong> 按钮，直接输入标题和 Markdown 内容：</p><ul><li>标题会成为条目的 Key</li><li>内容支持完整的 Markdown 语法</li><li>可以手动添加标签进行分类</li></ul><p><strong>方式二：批量导入文件</strong></p><p>支持拖放或选择文件批量导入：</p><ul><li><strong>Markdown / 文本文件</strong>：直接导入为条目内容</li><li>导入时自动提取内容中的第一个一级标题作为 Key</li><li>支持自动提取 <code>Tags:</code> 或 <code>标签:</code> 标记</li><li>可以开启<strong>去重</strong>功能，避免重复导入</li></ul><blockquote><p>TODO: 截图 - 工作区界面，标注添加条目按钮和文件拖放区域</p></blockquote><h3 id="第四步-向量化-建立索引" tabindex="-1">第四步：向量化（建立索引） <a class="header-anchor" href="#第四步-向量化-建立索引" aria-label="Permalink to &quot;第四步：向量化（建立索引）&quot;">​</a></h3><p>导入内容后，条目处于&quot;待向量化&quot;状态。你需要将其转换为向量才能进行语义搜索：</p><ul><li><strong>自动向量化</strong>：可以在 <strong>设置</strong> 中开启&quot;导入时自动向量化&quot;，导入后自动开始</li><li><strong>手动向量化</strong>：点击 <strong>一键向量化</strong> 按钮，批量处理所有未向量化的条目；或在条目详情中点击 <strong>同步向量</strong> 按钮单条处理</li><li><strong>单条向量化</strong>：在条目详情页，点击 <strong>同步向量</strong> 按钮针对单条条目进行向量化</li></ul><p>向量化过程会在后台进行，可以在 <strong>监控</strong> 视图查看进度和状态。</p><blockquote><p>TODO: 截图 - 监控视图中的索引进度条</p></blockquote><h3 id="第五步-在聊天中使用-rag" tabindex="-1">第五步：在聊天中使用（RAG） <a class="header-anchor" href="#第五步-在聊天中使用-rag" aria-label="Permalink to &quot;第五步：在聊天中使用（RAG）&quot;">​</a></h3><p>知识库最强大的地方在于与 <strong>LLM Chat</strong> 的集成。</p><ol><li>打开 <strong>LLM Chat</strong>，在右侧上下文面板绑定你的知识库。</li><li>在对话或 System Prompt 中加入占位符 <code>【kb】</code>。</li><li>发送消息，系统会自动检索知识并注入到 AI 的大脑中。</li></ol><p>详细的集成技巧请参考 <a href="./agent-integration">Agent 集成</a>。</p><h2 id="界面导览" tabindex="-1">界面导览 <a class="header-anchor" href="#界面导览" aria-label="Permalink to &quot;界面导览&quot;">​</a></h2><p>知识库工具包含以下几个标签页：</p><table tabindex="0"><thead><tr><th>标签页</th><th>说明</th></tr></thead><tbody><tr><td><strong>工作区</strong></td><td>条目的浏览、管理、编辑和搜索的核心界面</td></tr><tr><td><strong>统计</strong></td><td>知识库的全局统计数据（条目数、向量化率、Token 消耗等）</td></tr><tr><td><strong>监控</strong></td><td>实时查看 RAG 链路日志、索引进度和系统消息</td></tr><tr><td><strong>实验室</strong></td><td>多引擎对比测试，同时使用不同引擎搜索同一问题做效果对比</td></tr><tr><td><strong>设置</strong></td><td>全局配置（模型、导入、向量化参数等）</td></tr></tbody></table><blockquote><p>TODO: 截图 - 工具整体界面，标注五个标签页</p></blockquote><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>深入了解<a href="./indexing">索引引擎</a> - 掌握向量化的各种策略和配置</li><li>学习<a href="./entry-management">条目管理</a> - 了解如何高效组织和维护知识库</li><li>探索<a href="./agent-integration">Agent 集成</a> - 让 AI 聊天助手直接访问你的知识库</li></ul>',46)])])}const p=o(l,[["render",n]]);export{h as __pageData,p as default};
